body:
Hi,

I'm trying to create a self-signed X.509 client-certificate in a browser (Firefox 34) instead of a server. Somehow I only get garbage instead of a certificate. Please have a look what I'm missing:

``` Javascript
<html>
    <head>
	<meta http-equiv="Content-Type" content="text/html; charset=utf-8">
	<meta name="author" content="Rene Bartsch, B.Sc. Informatics, <rene@bartschnet.de>">
	<noscript><div id="noscript">!!! Sorry, ECMAscript/Javascript not available !!!</div></noscript>
	<title>Generate X.509 client-certificate and register fingerprint in Namecoin blockchain</title>

	<!-- X.509 Forge Javascript libraries (https://github.com/digitalbazaar/forge) -->
	<script language="JavaScript" type="text/javascript" src="forge.min.js"></script>

	<!-- Javascript functions -->
	<script language="javascript" type="text/javascript">

/*
	    function registerInBlockchain(identity, fingerprint) {
		alert("Identity: " + identity + "\nFingerprint: " + fingerprint);
	    }
*/

	    function generateCertificate(identity, password) {


		// Generate 4096-bit RSA keypair
		alert("Generating RSA keypair. This can take a lot of time ...");
		var keys = forge.pki.rsa.generateKeyPair(512);

		// Create X.509 certificate
		var cert = forge.pki.createCertificate();

		// Add public key to certificate
		cert.publicKey = keys.publicKey;

		// Set serial number
		cert.serialNumber = 0;

		// Set certificate start date to NOW
		cert.validity.notBefore = new Date();

		// Set certificate end date lower than 36,000 blocks =~ 250 days
		cert.validity.notAfter = new Date();
// ToDo		cert.validity.notAfter.setFullYear(cert.validity.notBefore.getFullYear() + 1);

		// Set issuer and subject attributes
		var attrs = [{
			name: 'organizationName',
			value: 'InternetCommunity'
		    }, {
			shortName: 'OU',
			value: 'Namecoin'
		    }, {
			name: 'commonName',
			value: identity
		}];
		cert.setIssuer(attrs);
		cert.setSubject(attrs);

		// Add extensions
		cert.setExtensions([
		    {
			name: 'basicConstraints',
			cA: true
		    }, {
			name: 'keyUsage',
			keyCertSign: true,
			digitalSignature: true,
			nonRepudiation: true,
			keyEncipherment: true,
			dataEncipherment: true
		    }, {
			name: 'extKeyUsage',
			serverAuth: false,
			clientAuth: true,
			codeSigning: true,
			emailProtection: false,
			timeStamping: true
		    }, {
			name: 'nsCertType',
			client: true,
			server: false,
			email: false,
			objsign: true,
			sslCA: false,
			emailCA: false,
			objCA: false
		    }
		]);

		// self-sign certificate
		cert.sign(keys.privateKey, forge.md.sha256.create());

		// Convert Forge certificate to an ASN.1 X.509v3 object
//		var asn1Cert = forge.pki.certificateToAsn1(cert);

		// Convert ASN.1 to PKCS12 with private key and password
		var p12Asn1 = forge.pkcs12.toPkcs12Asn1(keys.privateKey, cert, password);

		// Convert to DER format
		var p12Der  = forge.asn1.toDer(p12Asn1).getBytes();

		// Encode with Base64
		var p12b64  = forge.util.encode64(p12Der);

		// Backup certificate on disk
		var p12 = p12b64;

		// Store certificate on disk
		var a = document.createElement('a');
		a.download = identity + ".p12";
		a.setAttribute('href','data:application/x-x509-user-cert,' + p12);
		a.appendChild(document.createTextNode('Click to Download Client Certificate'));
		document.body.appendChild(a);

		// Import certificate into browser
		// ToDo


		// Return certificate fingerprint in hexa-decimal notation
		var fingerprint_str = '';
		var fingerprint = forge.md.sha256.create();
		fingerprint.update(cert);
		for(pos = 0; fingerprint.digest().toHex().length > pos; pos += 2) {
		    fingerprint_str += fingerprint.digest().toHex().charAt(pos) + fingerprint.digest().toHex().charAt(pos + 1);
		    if((pos + 2) < fingerprint.digest().toHex().length) {
			fingerprint_str += ':';
		    }
		}
		return(fingerprint_str);


alert("test");
	    }


	    function getFormData() {

		var rpcaddress  = document.getElementById("rpcaddress").value;
		var rpcport     = document.getElementById("rpcport").value;
		var rpcuser     = document.getElementById("rpcuser").value;
		var rpcpassword = document.getElementById("rpcpassword").value;
		var identity    = document.getElementById("identity").value;
		var password1   = document.getElementById("password1").value;
		var password2   = document.getElementById("password2").value;

		alert(
		      "\nRPCAddress:  " + rpcaddress
		    + "\nRPCPort:     " + rpcport
		    + "\nRPCUser:     " + rpcuser
		    + "\nRPCPassword: " + rpcpassword
		    + "\nIdentity:    " + identity
		    + "\nPassword1:   " + password1
		    + "\nPassword2:   " + password2
		);

		var fingerprint = generateCertificate(identity, password1);
		alert('Fingerprint: ' + fingerprint);
	    }

	</script>

    </head>
    <body>
	<form>
	    <div>RPCAddress:  <input type="text"     id="rpcaddress"  name="rpcaddress"  value="127.0.0.1"></div>
	    <div>RPCPort:     <input type="text"     id="rpcport"     name="rpcport"     value="8336"     ></div>
	    <div>RPCUser:     <input type="text"     id="rpcuser"     name="rpcuser"     value="renne"    ></div>
	    <div>RPCPassword: <input type="text"     id="rpcpassword" name="rpcpassword" value="0815"></div>
	    <div>Identity:    <select id="identity" name="identity">
		<option>renne</option>
	    </select></div>
	    <div>Password:    <input type="password" id="password1"   name="password1"   value="0815"></div>
	    <div>Password:    <input type="password" id="password2"   name="password2"   value="0815"></div>
	    <div><input type="button" value="OK" onclick="getFormData();"></div>
	</form>
	<div id="certificate"></div>
    </body>
</html>
```

@Diaoul has historically been pretty keen to just support the tip of released DSM versions (with updated toolchains/packages/etc), with backwards compatibility available when possible. If compatibility comes up, we always favoured the latest release and older releases potentially lost access to our packages.

There is some discussion in #939 and #982 about how we can handle situations where backwards compatibility is broken, but we still want to provide support for a large portion of the user base who haven't update yet.

I propose that we could implement some version handling in the framework and keep toolchain/kernel/package makefiles for several versions. There are many ways to pull this off, so it would be good to see a bit of discussion and a few different suggestions/angles before anyone tackles code.

One method that comes to mind is pushing makefiles one directory level deeper into a version folder (naming convention of synology DSM version, or synology "branch" number) with a symlink "latest" always pointing to the current latest supported version. We could then implement some variables to track what version of an SPK we want at compile time (latest, 4.3 [or 3776], all).

If DSM and the repo supports multiple versions of the same SPK (base on different FIRMWARE variable restrictions) then this could potentially appear seamless to the users - if not, we could provide "archived" direct download links on the spkrepo front end website)

@SynoCommunity/developers

@saivann If we were to make the change, "sell bitcoin" wouldn't be a typo as we are treating bitcoin as an uncountable noun e.g. "sell water", "sell bread". 

I would suggest that we do change the others to use the uncountable form as it more accurately represents bitcoins divisibility and may lead to less doubt among new users.

This is of course up to you and I will gladly change it to "bitcoins" if you chose.
